impl Solution { pub fn min_reorder(n: i32, connections: Vec<Vec<i32>>) -> i32 { let (mut black_adj, mut black_res, mut black_q, mut black_vis) = (vec![vec![]; n as usize], 0, std::collections::VecDeque::from([0]), vec![false; n as usize]); for black_c in connections { black_adj[black_c[0] as usize].push((black_c[1] as usize, 1)); black_adj[black_c[1] as usize].push((black_c[0] as usize, 0)); } black_vis[0] = true; while let Some(black_u) = black_q.pop_front() { for &(black_v, black_cost) in &black_adj[black_u] { if !black_vis[black_v] { black_res += black_cost; black_vis[black_v] = true; black_q.push_back(black_v); } } } black_res } }